/*主函数*/
void app_main(void)
{
    uint8_t image_cnt = 0 ;  // 图片计数器
    lcd_init();  // 初始化LCD
    while (1)
    { 
        image_cnt++;  // 图片计数器加1
        switch (image_cnt)
        {
        case 1:
            lcd_show_picture(gImage_1);  // 显示图片1
            break;
        case 2:
            lcd_show_picture(gImage_2);  // 显示图片2
            break;
        case 3:
            lcd_show_picture(gImage_3);  // 显示图片3
            break;
        case 4:
            lcd_show_picture(gImage_4);  // 显示图片4
            break;
        case 5:
            lcd_show_picture(gImage_5);  // 显示图片5
            break;
        case 6:
            lcd_show_picture(gImage_6);  // 显示图片6
            image_cnt = 0 ;  // 重置计数器
            break;
        default:
            break;
        }
        vTaskDelay(100);  // 延时100ms
    }
}